{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires a balance between spatial partitioning (to prevent overlap) and area optimization (to satisfy advertiser targets). I am decomposing this into a geometric partitioning task and a local area optimization task.",
  "helpers": [
    {
      "label": "spatial_partitioner",
      "instructions": "Implement a recursive spatial decomposition algorithm (such as a k-d tree or a quadtree) to partition the 10000x10000 grid into non-overlapping rectangular cells. Each cell must be assigned to exactly one advertiser's requested point. The partitioning logic must ensure that the resulting cells are axis-aligned and that the density of cells is higher in regions with a higher concentration of requested points to minimize wasted space."
    },
    {
      "label": "area_optimizer",
      "instructions": "Given a set of fixed rectangular boundaries (cells) from the spatial partitioner, perform a local optimization for each rectangle. For each advertiser, adjust the rectangle's dimensions (width and height) such that the rectangle remains within its assigned cell, contains its requested point, and the area is as close as possible to its requested target area. If the target area is larger than the cell, maximize the cell area; if smaller, minimize the deviation from the target area while maintaining the point containment constraint."
    }
  ],
  "synthesis_brief": "The parent agent will take the initial spatial partitions from the spatial_partitioner and pass the resulting bounding boxes and advertiser constraints to the area_optimizer. The final output will be the set of optimized rectangle coordinates (x1, y1, x2, y2) for each advertiser."
}
```

